var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"으윽……!","JPN":"ううっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_EP9HALF_NULL_NULL","text":{"KOREA":"어이구, 이 멍청한 양반아. 어째 뼈다귀들까지 주인 닮아서 자유분방한 망나니들뿐이야.","JPN":"まったく、アホったれ。骨も主に似て自由奔放なやつばかりときた。","ENG":"Ugh, you idiot... Even your bones seem to be as free-spirited as you.","TWN":"哎呀呀，你這傻小子，竟然連骨頭也跟主人一樣，都是些自由奔放的傢伙。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_EP9HALF_NULL_NULL","text":{"KOREA":"하여튼 면허 취소되고 받는 환자 놈들은 하나같이 살기 싫은 것 같아.","JPN":"免許を取り消されてからの患者はみんな生きたくないみたいだぜ。","ENG":"After having my license revoked, it seems that every patient I see has a death wish.","TWN":"總之我的執照被吊銷後，收到的病患淨是些不想活命的傢伙。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……떠들 시간에 마취나 잘해 주지. 살 째는 감각이 생생하던데.","JPN":"……しゃべってる間にちゃんと麻酔してくれ。肌を切る感覚がそのまま感じられるんだが。","ENG":"...How about less scolding and more painkillers? I could feel the blade running across my skin and bone.","TWN":"……在你囉嗦的同時可以幫我打個麻醉嗎？我完全可以感受到你在切我的肉欸？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_EP9HALF_NULL_NULL","text":{"KOREA":"말 걸지 마, 정신 사납게. 내 손 미끄러지면 너 평생 휠체어 타고 다니는 거야.","JPN":"話しかけんな、気が散る。俺の手が滑ったらお前さんは一生車椅子生活だぞ。","ENG":"Stop talking, I can't concentrate! If I make a mistake, you'll be in a wheelchair for the rest of your life.","TWN":"別和我說話，我要專心。要是我一個手滑，你可能下半輩子就要坐輪椅囉。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"표정이 왜 그래요, 언니? 대장이 잘못될까 봐 그래?","JPN":"どうしてそんな顔してるんですか、ユリさん？　隊長が心配だから？","ENG":"What's wrong, Yuri? Are you worried about Captain?","TWN":"姊姊，你怎麼那副表情？是擔心隊長出什麼事嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아니. 좀 생각할 게 있었어.","JPN":"いや。ちょっと思うところがあって。","ENG":"No, I just have a lot on my mind.","TWN":"不是，我在想其他事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장 수술 끝나면 너도 가서 진료 받아. 알파트릭스 녀석들과 싸울 때 총에 맞았잖아.","JPN":"隊長の手術が終わったらあなたも診察を受けな。アルファトリックスのやつらと戦ってる時に銃に撃たれただろ。","ENG":"Once he's done, you should get that gunshot wound checked as well.","TWN":"等隊長手術結束後，你也去治療一下吧。和阿爾法崔克斯的傢伙打鬥時你不是也有中槍嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"헤헷, 그거라면 걱정 마요. 언니.","JPN":"へへっ、それなら心配ご無用です。","ENG":"Hehe, you don't have to worry about me.","TWN":"嘿嘿，這你不用擔心啦，姊姊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"여기 보다시피 다……","JPN":"ほら、見てのとおり全部……","ENG":"As you can see, I'm all─","TWN":"你看，這裡都……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니? 왜 갑자기 총을 다 겨누고 그래, 무섭게.","JPN":"ユリさん？　なんでいきなり銃を構えるんですか？　怖いですよ。","ENG":"Yuri? Why are you pointing a gun at me? It's scaring me...","TWN":"姊姊？為何突然拿槍指著我？好嚇人喔。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……생각 중이었어. 같이 폭발에 휘말린 대장은 저렇게 골골거리는데, 넌 왜 멀쩡한지.","JPN":"……考えてたんだ。一緒に爆発に巻き込まれた隊長はああなったのに、なんでお前はなんともないのか。","ENG":"I've been thinking. Both you and Captain were caught in the blast. But he's barely alive, while you're not even scathed.","TWN":"……我一直在想，你和隊長明明就是同時被爆炸波及，為何隊長傷得那麼嚴重，你卻一點事都沒有？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"답은 의외로 가까이 있더군.","JPN":"答えは以外と簡単だった。","ENG":"Turns out the answer wasn't too far away.","TWN":"沒想到答案這麼簡單。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"카운터라서?","JPN":"カウンターだから？","ENG":"Because I'm a Counter?","TWN":"因為我是制裁者嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"맞아. 그리고 넌 여지껏 네가 카운터라는 말은 한마디도 하지 않았지.","JPN":"そう。それにお前は今まで自分がカウンターだなんてことは一言も言わなかった。","ENG":"Yeah. And you haven't said a word about it.","TWN":"沒錯，你至今從未提起你是制裁者的事吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"카운터를 사냥하는 사람들에게 카운터라고 밝혀 봤자 좋을 것 없잖아.","JPN":"カウンターを狩る人たちにカウンターって言ってもいいことないでしょ。","ENG":"Well, I don't think it's necessary to tell Counter-hunters that I'm a Counter as well, right?","TWN":"告訴專門獵殺制裁者的人我是制裁者，這件事完全沒好處的嘛。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"애초에 의뢰인을 덜컥 죽인 것도 수상해.","JPN":"そもそも依頼人を殺したことも怪しい。","ENG":"Also, it's suspicious that you killed our client just like that.","TWN":"先前突然殺掉委託人也可疑。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"왜 우리에게 접근했지? 어디서 보낸 프락치라도 되는 거야?","JPN":"何の目的で私たちに接近した？　どこかが送り込んだ組織のスパイなのか？","ENG":"Why did you approach us? Are you a spy?","TWN":"你為何要接近我們？是誰派你來臥底的嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에이, 너무 갔다. 어떤 바보가 이런 블링블링한 패션으로 잠입해. 그쵸?","JPN":"ええ、それはないですよ。どこのバカがこんな派手なファッションで潜入するの？　違います？","ENG":"Oh, come on. That's taking it way too far. Who'd be stupid enough to wear all this bling and be a spy? Right?","TWN":"哎呀，好過分，哪個傻瓜會穿得這麼漂亮來臥底？你說是嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"민병대에 들어온 이유는 간단해. 동생을 찾기 위해서야.","JPN":"民兵隊に入った理由は簡単。妹を探すためです。","ENG":"The reason why I joined the Militia is simple. I'm looking for my younger sister.","TWN":"我進入民兵隊的理由很簡單，就是要找我妹妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"나더러 그 말을 믿으라고? 네 동생이 우리 일과 무슨 상관인데?","JPN":"私にそれを信じろと？　お前の妹と私たちの仕事が何の関係がある。","ENG":"And you want me to believe that? What does your sister have to do with us anyway?","TWN":"你以為我會相信嗎？你妹妹和我們有什麼關係？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그 애라면 뭔가를 죽이는 일에 환장해 있을 거라고 생각했거든.","JPN":"あの子なら何かを殺すことに没頭してると思ったんですよね。","ENG":"Well, I thought she'd be obsessed with killing things.","TWN":"我原本以為她會在瘋狂地殺某種東西。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"침식체든, 인간이든, 뭐든.","JPN":"侵食体でも、人間でも、何でも。","ENG":"C.O.s, humans, or anything.","TWN":"不管是侵蝕體或是人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"침식체는 잠잠해졌으니까 이제 인간 차례려나 싶었지.","JPN":"侵食体はもう大人しくなったから、これからは人間の番かなーって。","ENG":"And since there aren't many C.O.s around, I thought she might be killing humans now.","TWN":"但侵蝕體沒什麼動靜，我才想說會是人嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 너 지금 그게……!","JPN":"何だと？　今それが……！","ENG":"What?! You can't be─!","TWN":"什麼？你那是……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"알아. 말도 안 되는 소리 같지?","JPN":"わかってますよ。あり得ないと思ったでしょ？","ENG":"I know. It sounds ridiculous, right?","TWN":"我知道，很荒謬對吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"하지만 정말이야. 동생은 뭔가를 죽이는 데 빠져 있을 수밖에 없거든요.","JPN":"でも本当だもん。妹は何かを殺すことに没頭するしかないんです。","ENG":"But I'm telling you the truth. You see, my sister can't help herself when it comes to killing.","TWN":"但我是說真的，我妹妹只能沉迷於殺某種東西，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"한 군데에 머물러 있어서는 욕구 불만에 빠질 만큼.","JPN":"一カ所に留まってると欲求不満になるくらい。","ENG":"To the extent that she even gets frustrated if she stays in one place for too long.","TWN":"要是停留在一個地方，她的渴望就無法被滿足。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"네 말대로라면…… 그냥 미치광이잖아? 그런 애를 왜 찾겠다는 거야?","JPN":"お前の話どおりなら……ただの狂人だろう？　なんでそんな子を探してるんだ？","ENG":"If that's true, then... She's just insane! Why would you even go look for her?","TWN":"照你的話聽起來……她就是個單純的瘋子吧？你幹嘛要找一個瘋子？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"동생이랑 전 둘이서 하나고, 하나이자 둘인 것 같은 사이니까.","JPN":"妹と私は二人でありながら一人、一人でありながら二人のような関係だから。","ENG":"She and I are one. We are two halves of a whole.","TWN":"因為我和妹妹二個是一體，是一體也是二個個體。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"저는 힘이 없고. 걔는 정신이 없고.","JPN":"私には力がなく、あの子には心がない。","ENG":"I have no power, and she lacks reasoning.","TWN":"我是沒有力量，她則是沒有意志。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"결국 내가 되찾지 않으면, 영원히 그렇게 살아야 할 팔자랄까?","JPN":"結局私が取り戻さないと、永遠にそう生きなきゃダメって感じですかね？","ENG":"If I don't find her, she'll end up having to live the rest of her life like that.","TWN":"應該是說，要是我不把她找回來，就必須永遠這樣活著嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그래서 처음엔 그 애를 봤다는 소문을 찾아다녔는데……","JPN":"それで最初はあの子を見たっていう噂を探し回ってたんだけど……","ENG":"So at first I looked around for places where there were rumors about sightings of her...","TWN":"所以我一開始到處打聽她的消息……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"갑자기 행적이 뚝 끊어졌더라고.","JPN":"いきなり足取りがばたっと無くなったの。","ENG":"But then, all of a sudden, all traces of her just vanished.","TWN":"後來突然就消聲匿跡，"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"꼭 누가 데려가기라도 한 것처럼.","JPN":"まるで誰かが連れて行ったみたいに。","ENG":"As if someone had taken her in.","TWN":"似乎是被誰帶走的感覺。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"에헤헤. 제 말 안 믿기시죠, 언니?","JPN":"えへへ。私の言葉、信じられないですよね？　ユリさん。","ENG":"Hehehe. You still don't believe me, though, do you?","TWN":"嘿嘿嘿，姊姊，你不相信我說的對吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"솔직히 말하면 믿고 싶은 생각도, 그래야 할 필요도 못 느껴.","JPN":"正直に言うと信じたいとも、そうする必要性も感じない。","ENG":"To be honest, I don't really want to believe you, nor do I feel the need to.","TWN":"老實說，我連必須要相信你的想法都沒有。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"정체를 숨긴 시점에서 너와 함께 움직일 수는 없으니까.","JPN":"正体を隠した時点でお前と行動を共にするわけにはいかないから。","ENG":"Now that I know you're hiding something, we can't work together anymore.","TWN":"因為打從你隱瞞真實身分開始，我就無法再和你一起行動。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"으응, 막내로서 되게 잘했다고 생각하는데.","JPN":"うーん、末っ子としてよくやってきたと思うけど。","ENG":"Hmm, I thought I did a great job as a rookie.","TWN":"嗯嗯，我還想說我這個老么的角色扮演得很好呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그건 나도 같은 생각이다. 이유리.","JPN":"俺もそう思っているぞ、カスカベ。","ENG":"I have to agree with you on that, Yuri.","TWN":"我和她的想法一樣，李悠麗。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장……?!","JPN":"隊長……！？","ENG":"Captain...?!","TWN":"隊長……？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"수술 받은 데는 어때요? 벌써부터 걸어다녀도 괜찮아요?","JPN":"手術したところはどうですか？　もう歩いてもいいんですか？","ENG":"How did the surgery go? Are you sure you should be walking so soon?","TWN":"手術完後還好嗎？已經可以走動了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 한가하게 병문안이나 받고 있을 시간은 없으니까.","JPN":"ああ。のんびり見舞われてる時間はないからな。","ENG":"I'm fine. Besides, I don't have the luxury of resting on the bed.","TWN":"嗯嗯，我現在可沒時間接受慰問。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"얘기는 들었다, 이유리. 하지만 멤버를 정하는 건 리더 몫이야.","JPN":"話は聞いたぞ、カスカベ。だがメンバーを決めるのはリーダーの役割だ。","ENG":"I overheard you both talking. But it's up to the leader to decide who stays and goes.","TWN":"我有聽到你們的對話，李悠麗。不過成員去留的決定權在於隊長。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이 지경이 됐는데 저런 수상한 애를 데리고 다니자고?","JPN":"こんな様になったのにあんな怪しいやつを連れて回るつもりなのか？","ENG":"Are you seriously considering bringing this suspicious girl along with us?","TWN":"事到如今，你還要帶著一個信不過的人一起行動嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레비아에게 했던 말을 그대로 돌려줘야겠군.","JPN":"レヴィアに言った言葉をそのまま返そう。","ENG":"I'll tell you the same thing I told Levia.","TWN":"我要把對莉維亞說過的話原封不動地對你說。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"베로니카를 상대해 봤으니 알겠지? 사람 죽이는 걸로는 성냥팔이 이상이야.","JPN":"ベロニカの相手をしてみたならわかってるだろう？　人を殺すことにかけてはマッチ売りより上だ。","ENG":"You faced Veronica, so you should know. Her ability to kill is beyond that of Matchmaker.","TWN":"你也和貝洛妮卡交手過，應該很清楚，她可是在專門殺人的賣火柴的之上。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우리에겐 지금 한 명이 아쉬운 상황이다.","JPN":"俺たちは今人手が必要だ。","ENG":"Right now, we need all the help we can get.","TWN":"我們現在不能失去任何一個人力。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"우리가 아니라 대장에게 그런 거 아니야?","JPN":"私たちじゃなくて隊長が、じゃないのか？","ENG":"You're the one who feels that way, not us.","TWN":"不是我們，而是對隊長而言吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너야말로 너무 감정적으로 굴지 마라. 의뢰인 건은 나도 아쉽게 생각하고 있어.","JPN":"お前こそあまり感情的に行動するな。依頼人の件は俺も残念だと思ってる。","ENG":"Don't let your emotions get the better of you. I regret what happened to our client, too.","TWN":"你先不要意氣用事，委託人的事我也很感到很遺憾。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 그 사람이 내통하지 않았다는 보장도 없지 않나?","JPN":"だがあの人が内通していなかったという保証もないだろう。","ENG":"However, there is no guarantee that he wasn't going to go behind our backs.","TWN":"但也沒有證據證明他真的不是內鬼吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"那是……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"저기, 언니. 보통 사람 감각으로 이해할 수 없다는 건 저도 알아요.","JPN":"あのね、ユリさん。普通の人間の感覚では理解できないというのは私もわかります。","ENG":"Look, Yuri. I know it's difficult for a normal person to understand.","TWN":"姊姊，我也知道，這件事以一般人的想法很難理解，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"하지만 전 진짜 동생을 되찾고 싶을 뿐이에요.","JPN":"でも私は本当に妹を取り戻したいだけなんです。","ENG":"But all I really want is to find my sister.","TWN":"但我真的只是想找回妹妹而已。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"그게…… 동생을 멈출 수 있는 길이니까요.","JPN":"それが……妹を止めることのできる道ですから。","ENG":"Because... That's the only way I'll be able to stop her.","TWN":"唯有這樣……才能阻止妹妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네 지적은 새겨 듣지.","JPN":"お前の指摘は肝に銘じておこう。","ENG":"I'll keep your word in mind.","TWN":"你的指教我會銘記在心，"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 지금은 우리가 하기로 한 일부터 끝낸다.","JPN":"だが今は俺たちのやるべきことから終わらせる。","ENG":"But for now, we need to finish what we started.","TWN":"但現在的重點是要完成我們的任務。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_DOOR_CAR"},{"id":"L36_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이건…… 베로니카잖아? 서버실에서 입수한 영상이야?","JPN":"これは……ベロニカ？　サーバー室から入手した映像なのか？","ENG":"Isn't that... Veronica? You were able to get the footage from the server room?","TWN":"這……不是貝洛妮卡嗎？這是在機房裡拿到的影片嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 녀석들이 가진 CCTV만 해도 한 나라를 전부 뒤덮고 남겠더군.","JPN":"ああ。やつらが持っているCCTVの映像だけでも一国を覆せるほどだった。","ENG":"Yeah. Turns out Alphatrix has enough security cameras to cover the entire nation.","TWN":"沒錯，他們的CCTV根本覆蓋整個國家。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"어쩜, 그 짧은 시간 안에 정말 잘 찾으셨다.","JPN":"まあ、あの短い時間に本当によく探せましたね。","ENG":"Wow... Props to you for finding it in such a short amount of time.","TWN":"哇，竟然可以在那麼短的時間內找到，厲害喔。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그래서 여기가 어디야? 영상만 봤을 때는 무슨 선착장 같은데.","JPN":"それで、あれがここだっていうのか？　映像を見たかぎりではどこかの船着き場みたいだけど。","ENG":"So? Where is this? It looks like some kind of dock?","TWN":"所以這裡就是這裡嗎？影片裡的地方看起來像是某個碼頭。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"맞아. 그라운드 원으로 가는 선착장이다.","JPN":"ああ。グラウンド・ワンに向かう船着き場だ。","ENG":"That's right. It's the docks that lead to Ground One.","TWN":"正確，是前往G1的碼頭，"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지금부터 우리가 가야 할 곳이지.","JPN":"今から俺たちが向かうべきところさ。","ENG":"That is where we need to go right now.","TWN":"也是我們接下來要前往的地方。"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};